from flask import Flask, request, redirect, session, render_template, url_for, flash
from flask_sqlalchemy import SQLAlchemy
from werkzeug.security import generate_password_hash, check_password_hash
import pyotp
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
db = SQLAlchemy(app)

class User(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    username = db.Column(db.String(80), unique=True, nullable=False)
    password = db.Column(db.String(128), nullable=False)
    mfa_secret = db.Column(db.String(16), nullable=False)

@app.before_first_request
def create_tables():
    db.create_all()

@app.route('/register', methods=['POST'])
def register():
    username = request.form['username']
    password = request.form['password']
    mfa_secret = pyotp.random_base32()
    hashed_password = generate_password_hash(password)
    new_user = User(username=username, password=hashed_password, mfa_secret=mfa_secret)
    db.session.add(new_user)
    db.session.commit()
    return 'User registered', 201

@app.route('/login', methods=['POST'])
def login():
    username = request.form['username']
    password = request.form['password']
    user = User.query.filter_by(username=username).first()
    if user and check_password_hash(user.password, password):
        session['username'] = username
        session['mfa_secret'] = user.mfa_secret
        return redirect(url_for('verify_mfa'))
    flash('Invalid username or password')
    return redirect(url_for('login'))

@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if request.method == 'POST':
        token = request.form['token']
        mfa_secret = session.get('mfa_secret')
        if pyotp.TOTP(mfa_secret).verify(token):
            session['authenticated'] = True
            return redirect(url_for('protected'))
        flash('Invalid MFA token')
    return render_template('verify_mfa.html')

@app.route('/protected')
def protected():
    if not session.get('authenticated'):
        return redirect(url_for('login'))
    return 'Protected resource accessed'

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))

if __name__ == '__main__':
    app.run(debug=True)